// // This module processes a 4-bit input and a 2-bit control signal to produce a 2-bit output. The output is determined by the following operations: right shift the input by 2 bits when the control signal is 00, perform a bitwise OR with the value 3 (binary 11) when the control signal is 01, invert the input bits when the control signal is 10, and perform a bitwise AND with the value 3 when the control signal is 11.
module top_module(
    input [3:0] data_in,
    input [1:0] ctrl,
    output reg [1:0] data_out
    );always @(*) begin
        case(ctrl)
            2'b00: data_out = data_in << 2;
            2'b01: data_out = data_in & 2'b11;
            2'b10: data_out = ~data_in;
            2'b11: data_out = data_in | 2'b11;
        endcase
    end

endmodule
